   177→interface DiagnosticPerformanceData extends TsDiagnosticPerformanceData {
   178→	fileLineCount?: number;
   179→}
   180→
   181→class DiagnosticsTelemetryManager extends Disposable {
   182→
   183→	private readonly _diagnosticCodesMap = new Map<number, number>();
   184→	private readonly _diagnosticSnapshotsMap = new ResourceMap<readonly vscode.Diagnostic[]>(uri => uri.toString(), { onCaseInsensitiveFileSystem: false });
   185→	private _timeout: NodeJS.Timeout | undefined;
   186→	private _telemetryEmitter: NodeJS.Timeout | undefined;
   187→
   188→	constructor(
   189→		private readonly _telemetryReporter: TelemetryReporter,
   190→		private readonly _diagnosticsCollection: vscode.DiagnosticCollection,
   191→	) {
   192→		super();
   193→		this._register(vscode.workspace.onDidChangeTextDocument(e => {
   194→			if (e.document.languageId === 'typescript' || e.document.languageId === 'typescriptreact') {
   195→				this._updateAllDiagnosticCodesAfterTimeout();
   196→			}
   197→		}));
   198→		this._updateAllDiagnosticCodesAfterTimeout();
   199→		this._registerTelemetryEventEmitter();
   200→	}
   201→
   202→	public logDiagnosticsPerformanceTelemetry(performanceData: DiagnosticPerformanceData[]): void {
   203→		for (const data of performanceData) {
   204→			/* __GDPR__
   205→				"diagnostics.performance" : {
   206→					"owner": "mjbvz",
   207→					"syntaxDiagDuration" : { "classification": "SystemMetaData", "purpose": "FeatureInsight", "isMeasurement": true },
   208→					"semanticDiagDuration" : { "classification": "SystemMetaData", "purpose": "FeatureInsight", "isMeasurement": true },
   209→					"suggestionDiagDuration" : { "classification": "SystemMetaData", "purpose": "FeatureInsight", "isMeasurement": true },
   210→					"regionSemanticDiagDuration" : { "classification": "SystemMetaData", "purpose": "FeatureInsight", "isMeasurement": true },
   211→					"fileLineCount" : { "classification": "SystemMetaData", "purpose": "FeatureInsight", "isMeasurement": true },
   212→					"${include}": [
   213→						"${TypeScriptCommonProperties}"
   214→					]
   215→				}
   216→			*/
   217→			this._telemetryReporter.logTelemetry('diagnostics.performance',
   218→				{
   219→					syntaxDiagDuration: data.syntaxDiag,
   220→					semanticDiagDuration: data.semanticDiag,
   221→					suggestionDiagDuration: data.suggestionDiag,
   222→					regionSemanticDiagDuration: data.regionSemanticDiag,
   223→					fileLineCount: data.fileLineCount,
   224→				},
   225→			);
   226→		}
   227→	}
   228→
   229→	private _updateAllDiagnosticCodesAfterTimeout() {
   230→		clearTimeout(this._timeout);
   231→		this._timeout = setTimeout(() => this._updateDiagnosticCodes(), 5000);
   232→	}
   233→
   234→	private _increaseDiagnosticCodeCount(code: string | number | undefined) {
   235→		if (code === undefined) {
   236→			return;
   237→		}
   238→		this._diagnosticCodesMap.set(Number(code), (this._diagnosticCodesMap.get(Number(code)) || 0) + 1);
   239→	}
   240→
   241→	private _updateDiagnosticCodes() {
   242→		this._diagnosticsCollection.forEach((uri, diagnostics) => {
   243→			const previousDiagnostics = this._diagnosticSnapshotsMap.get(uri);
   244→			this._diagnosticSnapshotsMap.set(uri, diagnostics);
   245→			const diagnosticsDiff = diagnostics.filter((diagnostic) => !previousDiagnostics?.some((previousDiagnostic) => equals(diagnostic, previousDiagnostic)));
   246→			diagnosticsDiff.forEach((diagnostic) => {
   247→				const code = diagnostic.code;
   248→				this._increaseDiagnosticCodeCount(typeof code === 'string' || typeof code === 'number' ? code : code?.value);
   249→			});
   250→		});
   251→	}
   252→
   253→	private _registerTelemetryEventEmitter() {
   254→		this._telemetryEmitter = setInterval(() => {
   255→			if (this._diagnosticCodesMap.size > 0) {
   256→				let diagnosticCodes = '';
   257→				this._diagnosticCodesMap.forEach((value, key) => {
   258→					diagnosticCodes += `${key}:${value},`;
   259→				});
   260→				this._diagnosticCodesMap.clear();
   261→				/* __GDPR__
   262→					"typescript.diagnostics" : {
   263→						"owner": "aiday-mar",
   264→						"diagnosticCodes" : { "classification": "PublicNonPersonalData", "purpose": "FeatureInsight" },
   265→						"${include}": [
   266→							"${TypeScriptCommonProperties}"
   267→						]
   268→					}
   269→				*/
   270→				this._telemetryReporter.logTelemetry('typescript.diagnostics', {
   271→					diagnosticCodes: diagnosticCodes
   272→				});
   273→			}
   274→		}, 5 * 60 * 1000); // 5 minutes
   275→	}
   276→
   277→	override dispose() {
   278→		super.dispose();
   279→		clearTimeout(this._timeout);
   280→		clearInterval(this._telemetryEmitter);
   281→	}
   282→}
   283→
   284→export class DiagnosticsManager extends Disposable {
   285→	private readonly _diagnostics: ResourceMap<FileDiagnostics>;
   286→	private readonly _settings = new DiagnosticSettings();
   287→	private readonly _currentDiagnostics: vscode.DiagnosticCollection;
   288→	private readonly _pendingUpdates: ResourceMap<any>;
   289→
   290→	private readonly _updateDelay = 50;
   291→
   292→	private readonly _diagnosticsTelemetryManager: DiagnosticsTelemetryManager | undefined;
   293→
   294→	constructor(
   295→		owner: string,
   296→		configuration: TypeScriptServiceConfiguration,
   297→		telemetryReporter: TelemetryReporter,
   298→		onCaseInsensitiveFileSystem: boolean
   299→	) {
   300→		super();
   301→		this._diagnostics = new ResourceMap<FileDiagnostics>(undefined, { onCaseInsensitiveFileSystem });
   302→		this._pendingUpdates = new ResourceMap<any>(undefined, { onCaseInsensitiveFileSystem });
   303→
   304→		this._currentDiagnostics = this._register(vscode.languages.createDiagnosticCollection(owner));
   305→		// Here we are selecting only 1 user out of 1000 to send telemetry diagnostics
   306→		if (Math.random() * 1000 <= 1 || configuration.enableDiagnosticsTelemetry) {
   307→			this._diagnosticsTelemetryManager = this._register(new DiagnosticsTelemetryManager(telemetryReporter, this._currentDiagnostics));
   308→		}
   309→	}
   310→
   311→	public override dispose() {
   312→		super.dispose();
   313→
   314→		for (const value of this._pendingUpdates.values()) {
   315→			clearTimeout(value);
   316→		}
   317→		this._pendingUpdates.clear();
   318→	}
   319→
   320→	public reInitialize(): void {
   321→		this._currentDiagnostics.clear();
   322→		this._diagnostics.clear();
   323→	}
   324→
   325→	public setValidate(language: DiagnosticLanguage, value: boolean) {
   326→		const didUpdate = this._settings.setValidate(language, value);
   327→		if (didUpdate) {
   328→			this.rebuildAll();
   329→		}
   330→	}
   331→
   332→	public setEnableSuggestions(language: DiagnosticLanguage, value: boolean) {
   333→		const didUpdate = this._settings.setEnableSuggestions(language, value);
   334→		if (didUpdate) {
   335→			this.rebuildAll();
   336→		}
   337→	}
   338→
   339→	public updateDiagnostics(
   340→		file: vscode.Uri,
   341→		language: DiagnosticLanguage,
   342→		kind: DiagnosticKind,
   343→		diagnostics: ReadonlyArray<vscode.Diagnostic>,
   344→		ranges: ReadonlyArray<vscode.Range> | undefined,
   345→	): void {
   346→		let didUpdate = false;
   347→		const entry = this._diagnostics.get(file);
   348→		if (entry) {
   349→			didUpdate = entry.updateDiagnostics(language, kind, diagnostics, ranges);
   350→		} else if (diagnostics.length) {
   351→			const fileDiagnostics = new FileDiagnostics(file, language);
   352→			fileDiagnostics.updateDiagnostics(language, kind, diagnostics, ranges);
   353→			this._diagnostics.set(file, fileDiagnostics);
   354→			didUpdate = true;
   355→		}
   356→
   357→		if (didUpdate) {
   358→			this.scheduleDiagnosticsUpdate(file);
   359→		}
   360→	}
   361→
   362→	public configFileDiagnosticsReceived(
   363→		file: vscode.Uri,
   364→		diagnostics: ReadonlyArray<vscode.Diagnostic>
   365→	): void {
   366→		this._currentDiagnostics.set(file, diagnostics);
   367→	}
   368→
   369→	public deleteAllDiagnosticsInFile(resource: vscode.Uri): void {
   370→		this._currentDiagnostics.delete(resource);
   371→		this._diagnostics.delete(resource);
   372→	}
   373→
   374→	public deleteDiagnostic(resource: vscode.Uri, diagnostic: vscode.Diagnostic): void {
   375→		const fileDiagnostics = this._diagnostics.get(resource);
   376→		if (fileDiagnostics) {
   377→			fileDiagnostics.delete(diagnostic);
   378→			this.rebuildFile(fileDiagnostics);
   379→		}
   380→	}
   381→
   382→	public getDiagnostics(file: vscode.Uri): ReadonlyArray<vscode.Diagnostic> {
   383→		return this._currentDiagnostics.get(file) || [];
   384→	}
   385→
   386→	public logDiagnosticsPerformanceTelemetry(performanceData: DiagnosticPerformanceData[]): void {
   387→		this._diagnosticsTelemetryManager?.logDiagnosticsPerformanceTelemetry(performanceData);
   388→	}
   389→
   390→	private scheduleDiagnosticsUpdate(file: vscode.Uri) {
   391→		if (!this._pendingUpdates.has(file)) {
   392→			this._pendingUpdates.set(file, setTimeout(() => this.updateCurrentDiagnostics(file), this._updateDelay));
   393→		}
   394→	}
   395→
   396→	private updateCurrentDiagnostics(file: vscode.Uri): void {
   397→		if (this._pendingUpdates.has(file)) {
   398→			clearTimeout(this._pendingUpdates.get(file));
   399→			this._pendingUpdates.delete(file);
   400→		}
   401→
   402→		const fileDiagnostics = this._diagnostics.get(file);
   403→		this._currentDiagnostics.set(file, fileDiagnostics ? fileDiagnostics.getAllDiagnostics(this._settings) : []);
   404→	}
   405→
   406→	private rebuildAll(): void {
   407→		this._currentDiagnostics.clear();
   408→		for (const fileDiagnostic of this._diagnostics.values()) {
   409→			this.rebuildFile(fileDiagnostic);
   410→		}
   411→	}
   412→
   413→	private rebuildFile(fileDiagnostic: FileDiagnostics) {
   414→		this._currentDiagnostics.set(fileDiagnostic.file, fileDiagnostic.getAllDiagnostics(this._settings));
   415→	}
   416→}
