    31→import { ActiveJsTsEditorTracker } from './ui/activeJsTsEditorTracker';
    32→import { IntellisenseStatus } from './ui/intellisenseStatus';
    33→import * as LargeProjectStatus from './ui/largeProjectStatus';
    34→import TypingsStatus, { AtaProgressReporter } from './ui/typingsStatus';
    35→import { VersionStatus } from './ui/versionStatus';
    36→import { coalesce } from './utils/arrays';
    37→import { Disposable } from './utils/dispose';
    38→
    39→// Style check diagnostics that can be reported as warnings
    40→const styleCheckDiagnostics = new Set([
    41→	...errorCodes.variableDeclaredButNeverUsed,
    42→	...errorCodes.propertyDeclaretedButNeverUsed,
    43→	...errorCodes.allImportsAreUnused,
    44→	...errorCodes.unreachableCode,
    45→	...errorCodes.unusedLabel,
    46→	...errorCodes.fallThroughCaseInSwitch,
    47→	...errorCodes.notAllCodePathsReturnAValue,
    48→]);
    49→
    50→export default class TypeScriptServiceClientHost extends Disposable {
    51→
    52→	private readonly client: TypeScriptServiceClient;
    53→	private readonly languages: LanguageProvider[] = [];
    54→	private readonly languagePerId = new Map<string, LanguageProvider>();
    55→
    56→	private readonly typingsStatus: TypingsStatus;
    57→
    58→	private readonly fileConfigurationManager: FileConfigurationManager;
    59→
    60→	private reportStyleCheckAsWarnings: boolean = true;
    61→
    62→	private readonly commandManager: CommandManager;
    63→
    64→	constructor(
    65→		descriptions: LanguageDescription[],
    66→		context: vscode.ExtensionContext,
    67→		onCaseInsensitiveFileSystem: boolean,
    68→		services: {
    69→			pluginManager: PluginManager;
    70→			commandManager: CommandManager;
    71→			logDirectoryProvider: ILogDirectoryProvider;
    72→			cancellerFactory: OngoingRequestCancellerFactory;
    73→			versionProvider: ITypeScriptVersionProvider;
    74→			processFactory: TsServerProcessFactory;
    75→			activeJsTsEditorTracker: ActiveJsTsEditorTracker;
    76→			serviceConfigurationProvider: ServiceConfigurationProvider;
    77→			experimentTelemetryReporter: IExperimentationTelemetryReporter | undefined;
    78→			logger: Logger;
    79→		},
    80→		onCompletionAccepted: (item: vscode.CompletionItem) => void,
    81→	) {
    82→		super();
    83→
    84→		this.commandManager = services.commandManager;
    85→
    86→		const allModeIds = this.getAllModeIds(descriptions, services.pluginManager);
    87→		this.client = this._register(new TypeScriptServiceClient(
    88→			context,
    89→			onCaseInsensitiveFileSystem,
    90→			services,
    91→			allModeIds));
    92→
    93→		this.client.onDiagnosticsReceived(({ kind, resource, diagnostics, spans }) => {
    94→			this.diagnosticsReceived(kind, resource, diagnostics, spans);
    95→		}, null, this._disposables);
    96→
    97→		this.client.onConfigDiagnosticsReceived(diag => this.configFileDiagnosticsReceived(diag), null, this._disposables);
    98→		this.client.onResendModelsRequested(() => this.populateService(), null, this._disposables);
    99→
   100→		this._register(new VersionStatus(this.client));
   101→		this._register(new IntellisenseStatus(this.client, services.commandManager, services.activeJsTsEditorTracker));
   102→		this._register(new AtaProgressReporter(this.client));
   103→		this.typingsStatus = this._register(new TypingsStatus(this.client));
   104→		this._register(LargeProjectStatus.create(this.client));
   105→
   106→		this.fileConfigurationManager = this._register(new FileConfigurationManager(this.client, onCaseInsensitiveFileSystem));
   107→
   108→		for (const description of descriptions) {
   109→			const manager = new LanguageProvider(this.client, description, this.commandManager, this.client.telemetryReporter, this.typingsStatus, this.fileConfigurationManager, onCompletionAccepted);
   110→			this.languages.push(manager);
   111→			this._register(manager);
   112→			this.languagePerId.set(description.id, manager);
   113→		}
   114→
   115→		import('./languageFeatures/updatePathsOnRename').then(module =>
   116→			this._register(module.register(this.client, this.fileConfigurationManager, uri => this.handles(uri))));
   117→
   118→		import('./languageFeatures/workspaceSymbols').then(module =>
   119→			this._register(module.register(this.client, allModeIds)));
   120→
   121→		this.client.ensureServiceStarted();
   122→		this.client.onReady(() => {
   123→			const languages = new Set<string>();
   124→			for (const plugin of services.pluginManager.plugins) {
   125→				if (plugin.configNamespace && plugin.languages.length) {
   126→					this.registerExtensionLanguageProvider({
   127→						id: plugin.configNamespace,
   128→						languageIds: Array.from(plugin.languages),
   129→						diagnosticSource: 'ts-plugin',
   130→						diagnosticLanguage: DiagnosticLanguage.TypeScript,
   131→						diagnosticOwner: 'typescript',
   132→						isExternal: true,
   133→						standardFileExtensions: [],
   134→					}, onCompletionAccepted);
   135→				} else {
   136→					for (const language of plugin.languages) {
   137→						languages.add(language);
   138→					}
   139→				}
   140→			}
   141→
   142→			if (languages.size) {
   143→				this.registerExtensionLanguageProvider({
   144→					id: 'typescript-plugins',
   145→					languageIds: Array.from(languages.values()),
   146→					diagnosticSource: 'ts-plugin',
   147→					diagnosticLanguage: DiagnosticLanguage.TypeScript,
   148→					diagnosticOwner: 'typescript',
   149→					isExternal: true,
   150→					standardFileExtensions: [],
   151→				}, onCompletionAccepted);
   152→			}
   153→		});
   154→
   155→		this.client.onTsServerStarted(() => {
   156→			this.triggerAllDiagnostics();
   157→		});
   158→
   159→		vscode.workspace.onDidChangeConfiguration(this.configurationChanged, this, this._disposables);
   160→		this.configurationChanged();
   161→		this._register(new LogLevelMonitor(context));
   162→	}
   163→
   164→	private registerExtensionLanguageProvider(description: LanguageDescription, onCompletionAccepted: (item: vscode.CompletionItem) => void) {
   165→		const manager = new LanguageProvider(this.client, description, this.commandManager, this.client.telemetryReporter, this.typingsStatus, this.fileConfigurationManager, onCompletionAccepted);
   166→		this.languages.push(manager);
   167→		this._register(manager);
   168→		this.languagePerId.set(description.id, manager);
   169→	}
   170→
   171→	private getAllModeIds(descriptions: LanguageDescription[], pluginManager: PluginManager) {
   172→		return [
   173→			...descriptions.map(x => x.languageIds),
   174→			...pluginManager.plugins.map(x => x.languages)
   175→		].flat();
   176→	}
   177→
   178→	public get serviceClient(): TypeScriptServiceClient {
   179→		return this.client;
   180→	}
   181→
   182→	public reloadProjects(): void {
   183→		this.client.executeWithoutWaitingForResponse('reloadProjects', null);
   184→		this.triggerAllDiagnostics();
   185→	}
   186→
   187→	public async handles(resource: vscode.Uri): Promise<boolean> {
   188→		const provider = await this.findLanguage(resource);
   189→		if (provider) {
   190→			return true;
   191→		}
   192→		return this.client.bufferSyncSupport.handles(resource);
   193→	}
   194→
   195→	private configurationChanged(): void {
   196→		const typescriptConfig = vscode.workspace.getConfiguration('typescript');
   197→
   198→		this.reportStyleCheckAsWarnings = typescriptConfig.get('reportStyleChecksAsWarnings', true);
   199→	}
   200→
   201→	private async findLanguage(resource: vscode.Uri): Promise<LanguageProvider | undefined> {
   202→		try {
   203→			// First try finding language just based on the resource.
   204→			// This is not strictly correct but should be in the vast majority of cases
   205→			// (except when someone goes and maps `.js` to `typescript` or something...)
   206→			for (const language of this.languages) {
   207→				if (language.handlesUri(resource)) {
   208→					return language;
   209→				}
   210→			}
   211→
   212→			// If that doesn't work, fallback to using a text document language mode.
   213→			// This is not ideal since we have to open the document but should always
   214→			// be correct
   215→			const doc = await vscode.workspace.openTextDocument(resource);
   216→			return this.languages.find(language => language.handlesDocument(doc));
   217→		} catch {
   218→			return undefined;
   219→		}
   220→	}
   221→
   222→	private triggerAllDiagnostics() {
   223→		for (const language of this.languagePerId.values()) {
   224→			language.triggerAllDiagnostics();
   225→		}
   226→	}
   227→
   228→	private populateService(): void {
   229→		this.fileConfigurationManager.reset();
   230→
   231→		for (const language of this.languagePerId.values()) {
   232→			language.reInitialize();
   233→		}
   234→	}
   235→
   236→	private async diagnosticsReceived(
   237→		kind: DiagnosticKind,
   238→		resource: vscode.Uri,
   239→		diagnostics: Proto.Diagnostic[],
   240→		spans: Proto.TextSpan[] | undefined,
   241→	): Promise<void> {
   242→		const language = await this.findLanguage(resource);
   243→		if (language) {
   244→			language.diagnosticsReceived(
   245→				kind,
   246→				resource,
   247→				this.createMarkerDatas(diagnostics, language.diagnosticSource),
   248→				spans?.map(span => typeConverters.Range.fromTextSpan(span)));
   249→		}
   250→	}
   251→
   252→	private configFileDiagnosticsReceived(event: Proto.ConfigFileDiagnosticEvent): void {
   253→		// See https://github.com/microsoft/TypeScript/issues/10384
   254→		const body = event.body;
   255→		if (!body?.diagnostics || !body.configFile) {
   256→			return;
   257→		}
   258→
   259→		this.findLanguage(this.client.toResource(body.configFile)).then(language => {
   260→			language?.configFileDiagnosticsReceived(this.client.toResource(body.configFile), body.diagnostics.map(tsDiag => {
   261→				const range = tsDiag.start && tsDiag.end ? typeConverters.Range.fromTextSpan(tsDiag) : new vscode.Range(0, 0, 0, 1);
   262→				const diagnostic = new vscode.Diagnostic(range, tsDiag.text, this.getDiagnosticSeverity(tsDiag));
   263→				diagnostic.source = language.diagnosticSource;
   264→				return diagnostic;
   265→			}));
   266→		});
   267→	}
   268→
   269→	private createMarkerDatas(
   270→		diagnostics: Proto.Diagnostic[],
   271→		source: string
   272→	): (vscode.Diagnostic & { reportUnnecessary: any; reportDeprecated: any })[] {
   273→		return diagnostics.map(tsDiag => this.tsDiagnosticToVsDiagnostic(tsDiag, source));
   274→	}
   275→
   276→	private tsDiagnosticToVsDiagnostic(diagnostic: Proto.Diagnostic, source: string): vscode.Diagnostic & { reportUnnecessary: any; reportDeprecated: any } {
   277→		const { start, end, text } = diagnostic;
   278→		const range = new vscode.Range(typeConverters.Position.fromLocation(start), typeConverters.Position.fromLocation(end));
   279→		const converted = new vscode.Diagnostic(range, text, this.getDiagnosticSeverity(diagnostic));
   280→		converted.source = diagnostic.source || source;
   281→		if (diagnostic.code) {
   282→			converted.code = diagnostic.code;
   283→		}
   284→		const relatedInformation = diagnostic.relatedInformation;
   285→		if (relatedInformation) {
   286→			converted.relatedInformation = coalesce(relatedInformation.map((info: any) => {
   287→				const span = info.span;
   288→				if (!span) {
   289→					return undefined;
   290→				}
   291→				return new vscode.DiagnosticRelatedInformation(typeConverters.Location.fromTextSpan(this.client.toResource(span.file), span), info.message);
   292→			}));
   293→		}
   294→		const tags: vscode.DiagnosticTag[] = [];
   295→		if (diagnostic.reportsUnnecessary) {
   296→			tags.push(vscode.DiagnosticTag.Unnecessary);
   297→		}
   298→		if (diagnostic.reportsDeprecated) {
   299→			tags.push(vscode.DiagnosticTag.Deprecated);
   300→		}
   301→		converted.tags = tags.length ? tags : undefined;
   302→
   303→		const resultConverted = converted as vscode.Diagnostic & { reportUnnecessary: any; reportDeprecated: any };
   304→		resultConverted.reportUnnecessary = diagnostic.reportsUnnecessary;
   305→		resultConverted.reportDeprecated = diagnostic.reportsDeprecated;
   306→		return resultConverted;
   307→	}
   308→
   309→	private getDiagnosticSeverity(diagnostic: Proto.Diagnostic): vscode.DiagnosticSeverity {
   310→		if (this.reportStyleCheckAsWarnings
   311→			&& this.isStyleCheckDiagnostic(diagnostic.code)
   312→			&& diagnostic.category === PConst.DiagnosticCategory.error
   313→		) {
   314→			return vscode.DiagnosticSeverity.Warning;
   315→		}
   316→
   317→		switch (diagnostic.category) {
   318→			case PConst.DiagnosticCategory.error:
   319→				return vscode.DiagnosticSeverity.Error;
   320→
   321→			case PConst.DiagnosticCategory.warning:
   322→				return vscode.DiagnosticSeverity.Warning;
   323→
   324→			case PConst.DiagnosticCategory.suggestion:
   325→				return vscode.DiagnosticSeverity.Hint;
   326→
   327→			default:
   328→				return vscode.DiagnosticSeverity.Error;
   329→		}
   330→	}
   331→
   332→	private isStyleCheckDiagnostic(code: number | undefined): boolean {
   333→		return typeof code === 'number' && styleCheckDiagnostics.has(code);
   334→	}
   335→}
