   141→	public diagnosticsReceived(
   142→		diagnosticsKind: DiagnosticKind,
   143→		file: vscode.Uri,
   144→		diagnostics: (vscode.Diagnostic & { reportUnnecessary: any; reportDeprecated: any })[],
   145→		ranges: vscode.Range[] | undefined): void {
   146→		if (diagnosticsKind !== DiagnosticKind.Syntax && !this.client.hasCapabilityForResource(file, ClientCapability.Semantic)) {
   147→			return;
   148→		}
   149→
   150→		if (diagnosticsKind === DiagnosticKind.Semantic && isWeb()) {
   151→			if (
   152→				!isWebAndHasSharedArrayBuffers()
   153→				|| !supportsReadableByteStreams() // No ata. Will result in lots of false positives
   154→				|| this.client.configuration.webProjectWideIntellisenseSuppressSemanticErrors
   155→				|| !this.client.configuration.webProjectWideIntellisenseEnabled
   156→			) {
   157→				return;
   158→			}
   159→		}
   160→
   161→		// Disable semantic errors in notebooks until we have better notebook support
   162→		if (diagnosticsKind === DiagnosticKind.Semantic && file.scheme === Schemes.notebookCell) {
   163→			return;
   164→		}
   165→
   166→		const config = vscode.workspace.getConfiguration(this.id, file);
   167→		const reportUnnecessary = config.get<boolean>('showUnused', true);
   168→		const reportDeprecated = config.get<boolean>('showDeprecated', true);
   169→		this.client.diagnosticsManager.updateDiagnostics(file, this._diagnosticLanguage, diagnosticsKind, diagnostics.filter(diag => {
   170→			// Don't bother reporting diagnostics we know will not be rendered
   171→			if (!reportUnnecessary) {
   172→				if (diag.reportUnnecessary && diag.severity === vscode.DiagnosticSeverity.Hint) {
   173→					return false;
   174→				}
   175→			}
   176→			if (!reportDeprecated) {
   177→				if (diag.reportDeprecated && diag.severity === vscode.DiagnosticSeverity.Hint) {
   178→					return false;
   179→				}
   180→			}
   181→			return true;
   182→		}), ranges);
   183→	}
