	private registerFileSystemWatcher(): void {
		// Create a file system watcher to listen for file changes (e.g., from git checkout)
		if (!vscode.workspace.workspaceFolders || vscode.workspace.workspaceFolders.length === 0) {
			return;
		}

		for (const folder of vscode.workspace.workspaceFolders) {
			// Create a watcher for TypeScript/JavaScript files in the workspace
			const watcher = this._register(vscode.workspace.createFileSystemWatcher(
				new vscode.RelativePattern(folder, '**/*.{ts,tsx,js,jsx}')
			));

			// When files change on disk, request fresh diagnostics
			this._register(watcher.onDidChange(uri => {
				this.onFileChanged(uri);
			}));

			// When files are deleted, clear their diagnostics
			this._register(watcher.onDidDelete(uri => {
				this.onFileDeleted(uri);
			}));
		}
	}

	private onFileChanged(uri: vscode.Uri): void {
		// Request diagnostics for the changed file
		this.client.bufferSyncSupport.getErr([uri]);
	}

	private onFileDeleted(uri: vscode.Uri): void {
		// Clear diagnostics for deleted files
		this.client.diagnosticsManager.deleteAllDiagnosticsInFile(uri);
	}
